import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { getCourseById, getCourseYears } from '../config/config';

const YearSelection = () => {
  const { courseId } = useParams();
  const navigate = useNavigate();
  const [years, setYears] = useState([]);
  const [course, setCourse] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchCourseData();
  }, [courseId]);

  const fetchCourseData = async () => {
    try {
      // Use config for course data
      const courseData = getCourseById(courseId);
      
      if (!courseData) {
        throw new Error('Course not found');
      }

      setCourse(courseData);

      // Create years array using config
      const yearsArray = getCourseYears(courseId).map(year => ({
        id: year.id,
        name: `Year ${year.id}`,
        subjects: year.id === 1 ? 8 : year.id === 2 ? 7 : 6,
        description: `${courseData.name} Year ${year.id} complete materials`,
        courses: year.id === 1 ? 'Basic' : year.id === 2 ? 'Intermediate' : 'Advanced'
      }));

      setYears(yearsArray);
    } catch (error) {
      console.error('Error fetching course data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleYearClick = (yearId) => {
    navigate(`/course/${courseId}/year/${yearId}`);
  };

  const handleBack = () => {
    navigate('/');
  };

  if (loading) {
    return (
      <div style={styles.loadingContainer}>
        <div style={styles.loadingSpinner}></div>
        <p>Loading course information...</p>
      </div>
    );
  }

  if (!course) {
    return (
      <div style={styles.errorContainer}>
        <h3>Course not found!</h3>
        <button onClick={handleBack} style={styles.backButton}>
          ← Back to Courses
        </button>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      {/* Header */}
      <div style={styles.header}>
        <button onClick={handleBack} style={styles.backButton}>
          ← Back to Courses
        </button>
        <div style={styles.courseInfo}>
          <span style={styles.courseIcon}>{course.icon}</span>
          <h1 style={styles.courseName}>{course.name}</h1>
          <p style={styles.courseDescription}>Select your academic year</p>
          <p style={styles.courseDetails}>
            {course.duration} Years • {course.totalSemesters} Semesters • {course.branches.length} Branches
          </p>
        </div>
      </div>

      {/* Years Grid */}
      <div style={styles.yearsGrid}>
        {years.map((year) => (
          <div
            key={year.id}
            style={styles.yearCard}
            onClick={() => handleYearClick(year.id)}
          >
            <div style={{
              ...styles.yearNumberCircle,
              background: `linear-gradient(135deg, ${course.color}40, ${course.color}80)`
            }}>
              <span style={styles.yearNumber}>{year.id}</span>
            </div>
            <h3 style={styles.yearName}>{year.name}</h3>
            <p style={styles.yearDescription}>{year.description}</p>
            <p style={styles.yearLevel}>Level: {year.courses}</p>
            
            <div style={styles.materialsPreview}>
              <span style={styles.materialBadge}>📋 Syllabus</span>
              <span style={styles.materialBadge}>📚 Notes</span>
              <span style={styles.materialBadge}>📝 PYQs</span>
              <span style={styles.materialBadge}>🔬 Labs</span>
            </div>

            <div style={styles.stats}>
              <span style={styles.stat}>📚 {year.subjects} Subjects</span>
              <span style={styles.stat}>📄 200+ Notes</span>
            </div>

            <button style={{
              ...styles.selectButton,
              background: `linear-gradient(90deg, ${course.color}, ${course.color}DD)`
            }}>
              Select Year {year.id} →
            </button>
          </div>
        ))}
      </div>

      {/* Course Info Footer */}
      <div style={styles.footer}>
        <p>
          <strong>{course.name}</strong> • {course.duration} Years • 
          {course.totalSemesters} Semesters • Complete study materials
        </p>
        <p style={{ fontSize: '0.9rem', marginTop: '0.5rem', color: '#6b7280' }}>
          Available branches: {course.branches.join(', ')}
        </p>
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem 1rem',
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #f8fafc 0%, #e2e8f0 100%)'
  },
  header: {
    marginBottom: '3rem',
    textAlign: 'center'
  },
  backButton: {
    padding: '0.75rem 1.5rem',
    background: '#4f46e5',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    fontSize: '1rem',
    marginBottom: '1rem',
    display: 'inline-block',
    transition: 'all 0.3s',
    '&:hover': {
      background: '#4338ca',
      transform: 'translateX(-5px)'
    }
  },
  courseInfo: {
    background: 'white',
    padding: '2rem',
    borderRadius: '15px',
    boxShadow: '0 5px 15px rgba(0,0,0,0.05)'
  },
  courseIcon: {
    fontSize: '3rem',
    marginBottom: '1rem',
    display: 'inline-block'
  },
  courseName: {
    fontSize: '2.5rem',
    marginBottom: '0.5rem',
    color: '#1f2937'
  },
  courseDescription: {
    color: '#6b7280',
    fontSize: '1.1rem',
    marginBottom: '0.5rem'
  },
  courseDetails: {
    color: '#4f46e5',
    fontSize: '0.9rem',
    fontWeight: '500'
  },
  yearsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '2rem',
    marginBottom: '3rem'
  },
  yearCard: {
    background: 'white',
    padding: '1.5rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px rgba(0,0,0,0.05)',
    textAlign: 'center',
    cursor: 'pointer',
    transition: 'all 0.3s ease',
    border: '2px solid transparent',
    '&:hover': {
      transform: 'translateY(-5px)',
      boxShadow: '0 10px 25px rgba(0,0,0,0.1)',
      borderColor: '#4f46e5'
    }
  },
  yearNumberCircle: {
    width: '60px',
    height: '60px',
    borderRadius: '50%',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    margin: '0 auto 1rem',
    color: 'white',
    fontSize: '1.5rem',
    fontWeight: 'bold'
  },
  yearNumber: {
    color: '#1f2937'
  },
  yearName: {
    fontSize: '1.5rem',
    marginBottom: '0.5rem',
    color: '#1f2937'
  },
  yearDescription: {
    color: '#6b7280',
    marginBottom: '0.5rem',
    fontSize: '0.9rem'
  },
  yearLevel: {
    color: '#4f46e5',
    fontSize: '0.8rem',
    fontWeight: '500',
    marginBottom: '1rem'
  },
  materialsPreview: {
    display: 'flex',
    justifyContent: 'center',
    flexWrap: 'wrap',
    gap: '0.5rem',
    margin: '1rem 0'
  },
  materialBadge: {
    background: '#f3f4f6',
    color: '#4b5563',
    padding: '0.25rem 0.75rem',
    borderRadius: '15px',
    fontSize: '0.75rem',
    border: '1px solid #e5e7eb'
  },
  stats: {
    display: 'flex',
    justifyContent: 'center',
    gap: '1rem',
    margin: '1rem 0',
    fontSize: '0.9rem',
    color: '#666'
  },
  stat: {
    background: '#f3f4f6',
    padding: '0.25rem 0.75rem',
    borderRadius: '15px'
  },
  selectButton: {
    marginTop: '1rem',
    padding: '0.75rem 1.5rem',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    cursor: 'pointer',
    fontSize: '1rem',
    width: '100%',
    fontWeight: '500',
    transition: 'all 0.3s',
    '&:hover': {
      transform: 'translateY(-2px)',
      boxShadow: '0 5px 15px rgba(0,0,0,0.1)'
